DELETE FROM castor_documents 
WHERE metadata->>'file_id' = '{{ $json.file_id }}'
AND (metadata->>'session_id' IS NULL OR metadata->>'session_id' = '');

-- ✅ Apenas garante índices. NÃO apaga dados.
-- A limpeza por-arquivo acontece em "Delete Old Doc Rows1" SOMENTE quando o arquivo mudou.
CREATE INDEX IF NOT EXISTS castor_idx_doc_metadata_session
ON castor_document_metadata(session_id);

CREATE INDEX IF NOT EXISTS castor_idx_doc_metadata_modified
ON castor_document_metadata(modified_time);

CREATE INDEX IF NOT EXISTS castor_idx_documents_metadata_gin
ON castor_documents USING GIN (metadata);

-- Índice para acelerar lookups por file_id no JSON metadata
CREATE INDEX IF NOT EXISTS castor_idx_documents_file_id
ON castor_documents ((metadata->>'file_id'));

-- ✅ Limpeza segura de DADOS DE SESSÃO (não toca em docs globais nem migrations).
-- Envolvido em DO/EXCEPTION para nunca quebrar o workflow se uma tabela legada não existir.
DO $$
BEGIN
  -- 1. Remove chat APENAS de sessões cujos docs já expiraram (não apaga histórico ativo)
  BEGIN
    DELETE FROM castor_chat_message
    WHERE session_id IN (
      SELECT session_id FROM castor_document_metadata WHERE session_id IS NOT NULL
    );
  EXCEPTION WHEN undefined_table THEN
    RAISE NOTICE 'castor_chat_message ausente — pulando';
  END;

  -- 2. Remove vetores de sessão
  BEGIN
    DELETE FROM castor_documents
    WHERE metadata->>'session_id' IS NOT NULL
      AND metadata->>'session_id' <> '';
  EXCEPTION WHEN undefined_table THEN
    RAISE NOTICE 'castor_documents ausente — pulando';
  END;

  -- 3. Remove metadados/linhas de sessão (rows caem via CASCADE)
  BEGIN
    DELETE FROM castor_document_metadata
    WHERE session_id IS NOT NULL;
  EXCEPTION WHEN undefined_table THEN
    RAISE NOTICE 'castor_document_metadata ausente — pulando';
  END;
END $$;

